    text-overflow: ellipsis;
    white-space: nowrap;
    margin-right: 12px;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 2px 10px;
    cursor: pointer;
    flex-shrink: 0;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

